/**
 * Animation Viewer — preview every clip on every character with feedback notes.
 */
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js';
import { AssetLoader } from './engine/AssetLoader.js';
import { ROSTER } from './data/characters.js';

const STORAGE_KEY = 'dsf.viewer.notes.v1';

const SOURCE_INFO = {
  abdullah_sherdil:  'Mixamo (Ch06) rig + 26 procedural animations',
  toofan_khan:       'Mixamo (Ch18) rig + 26 procedural animations',
  aslam_karachiwala: 'Quaternius rig + real Quaternius mocap',
  sher_khan_afridi:  'Quaternius rig + real Quaternius mocap',
  irfan_baloch:      'Quaternius rig + real Quaternius mocap',
  dr_hina:           'Mixamo female rig + 8 real Mixamo mocap + 18 procedural',
};

const CANONICAL_ANIMATIONS = [
  'idle',
  'walk_forward', 'walk_backward',
  'jump_up', 'jump_fall', 'land',
  'punch_light', 'punch_medium', 'punch_heavy',
  'kick_light', 'kick_medium', 'kick_heavy',
  'block_high', 'block_low', 'crouch',
  'hit_high', 'hit_low', 'knockdown', 'get_up',
  'taunt', 'intro', 'victory', 'defeat',
  'special_1', 'special_2', 'super_move',
];

// ---- DOM references (at the top — must precede any handler that uses them) ----

const canvas = document.getElementById('canvas');
const charListEl = document.getElementById('char-list');
const animListEl = document.getElementById('anim-list');
const overlayEl = document.getElementById('overlay');
const notesEl = document.getElementById('notes');
const notesSummaryEl = document.getElementById('notes-summary');
const curCharEl = document.getElementById('cur-char');
const curAnimEl = document.getElementById('cur-anim');
const curDurEl = document.getElementById('cur-dur');
const curSrcEl = document.getElementById('cur-src');
const speedEl = document.getElementById('speed');
const speedValEl = document.getElementById('speed-val');
const loopEl = document.getElementById('loop');
const playBtn = document.getElementById('play-btn');
const scrubEl = document.getElementById('scrub');
const frameValEl = document.getElementById('frame-val');
const exportBtn = document.getElementById('export-json');
const clearBtn = document.getElementById('clear-notes');

// Sanity: bail early if the DOM doesn't have what we expect, with a visible error
if (!canvas || !charListEl || !animListEl) {
  document.body.innerHTML =
    '<div style="padding:24px;font-family:system-ui;color:#ff9966;">' +
    'Viewer DOM not found. Reload the page.' +
    '</div>';
  throw new Error('Viewer DOM missing required elements');
}

function setOverlay(t) { if (overlayEl) overlayEl.textContent = t; }

// ---- Three.js scene ----

const renderer = new THREE.WebGLRenderer({ canvas, antialias: true });
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.outputColorSpace = THREE.SRGBColorSpace;

const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1a1208);

const camera = new THREE.PerspectiveCamera(40, 1, 0.1, 50);
camera.position.set(0, 1.4, 4);
camera.lookAt(0, 1.0, 0);

const ambient = new THREE.HemisphereLight(0xffd770, 0x2a1208, 0.9);
scene.add(ambient);
const key = new THREE.DirectionalLight(0xfff0c2, 1.6);
key.position.set(2.5, 4, 2.5);
scene.add(key);
const rim = new THREE.DirectionalLight(0xff8a3a, 0.6);
rim.position.set(-3, 2.5, -3);
scene.add(rim);

const groundGeo = new THREE.CircleGeometry(2.4, 48);
const groundMat = new THREE.MeshStandardMaterial({ color: 0x7a4a22, roughness: 0.95 });
const ground = new THREE.Mesh(groundGeo, groundMat);
ground.rotation.x = -Math.PI / 2;
scene.add(ground);

const controls = new OrbitControls(camera, canvas);
controls.target.set(0, 1.0, 0);
controls.minDistance = 1.5;
controls.maxDistance = 8;
controls.maxPolarAngle = Math.PI / 2 + 0.1;

function resize() {
  const w = canvas.clientWidth;
  const h = canvas.clientHeight;
  renderer.setSize(w, h, false);
  camera.aspect = w / h;
  camera.updateProjectionMatrix();
}
window.addEventListener('resize', resize);
resize();

// ---- State ----

const assetLoader = new AssetLoader();
let currentRig = null;
let currentAsset = null;
let currentCharacter = null;
let currentAction = null;
let currentClip = null;
let isPaused = false;
let scrubbing = false;

// ---- Notes ----

function loadNotes() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return {};
    const v = JSON.parse(raw);
    return v && typeof v === 'object' ? v : {};
  } catch { return {}; }
}
function saveNotes(n) {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(n)); }
  catch (e) { console.warn('Failed to save notes', e); }
}
function noteKey(charId, animName) { return `${charId}::${animName}`; }
let notesState = loadNotes();

function showNoteFor(charId, animName) {
  if (notesEl) notesEl.value = notesState[noteKey(charId, animName)] ?? '';
  renderNotesSummary();
  refreshAnimListMarkers();
}

function renderNotesSummary() {
  const entries = Object.entries(notesState);
  if (!notesSummaryEl) return;
  if (entries.length === 0) {
    notesSummaryEl.textContent = 'No notes yet.';
    return;
  }
  const byChar = {};
  for (const [k] of entries) {
    const [char] = k.split('::');
    byChar[char] = (byChar[char] || 0) + 1;
  }
  notesSummaryEl.innerHTML = Object.entries(byChar)
    .map(([c, n]) => `<div>${c}: <span style="color:#ffd770;">${n} note${n > 1 ? 's' : ''}</span></div>`)
    .join('');
}

// ---- Rig load + clip playback ----

function clearRig() {
  if (currentRig) {
    scene.remove(currentRig);
    currentRig.traverse((o) => {
      if (o.geometry) o.geometry.dispose?.();
      if (o.material) {
        if (Array.isArray(o.material)) o.material.forEach((m) => m.dispose?.());
        else o.material.dispose?.();
      }
    });
  }
  currentRig = null;
  currentAsset = null;
  currentAction = null;
  currentClip = null;
}

async function loadCharacter(charData) {
  setOverlay(`Loading ${charData.name}…`);
  clearRig();
  try {
    const asset = await assetLoader.loadCharacter({
      url: charData.model,
      animationMap: charData.animationMap,
    });
    currentAsset = asset;
    currentCharacter = charData;

    const rig = new THREE.Group();
    rig.add(asset.scene);
    const box = new THREE.Box3().setFromObject(asset.scene);
    const size = new THREE.Vector3();
    box.getSize(size);
    if (size.y > 0.0001) asset.scene.scale.setScalar(1.8 / size.y);
    box.setFromObject(asset.scene);
    asset.scene.position.y -= box.min.y;
    asset.scene.position.y += charData.yOffset ?? 0;
    rig.scale.setScalar(charData.scale ?? 1.0);

    scene.add(rig);
    currentRig = rig;

    updateRight();
    const firstAvailable = CANONICAL_ANIMATIONS.find((n) => asset.clips[n]);
    if (firstAvailable) playClipByName(firstAvailable);
    else setOverlay(`${charData.name} — no clips found`);
  } catch (err) {
    setOverlay(`Load error: ${err.message ?? err}`);
    console.error(err);
  }
}

function playClipByName(name) {
  if (!currentAsset) return;
  const clip = currentAsset.clips[name];
  if (!clip) {
    setOverlay(`${currentCharacter.name} · ${name} (missing)`);
    highlightActiveAnim(name);
    return;
  }
  if (currentAction) currentAction.stop();
  const action = currentAsset.mixer.clipAction(clip);
  action.reset();
  action.setLoop(loopEl.checked ? THREE.LoopRepeat : THREE.LoopOnce, Infinity);
  action.clampWhenFinished = !loopEl.checked;
  action.timeScale = +speedEl.value;
  action.play();
  currentAction = action;
  currentClip = clip;
  isPaused = false;
  playBtn.textContent = '⏸ Pause';
  scrubEl.max = clip.duration.toFixed(3);

  setOverlay(`${currentCharacter.name} · ${name}`);
  highlightActiveAnim(name);
  updateRight();
  showNoteFor(currentCharacter.id, name);
}

function updateRight() {
  curCharEl.textContent = currentCharacter?.name ?? '—';
  curAnimEl.textContent = currentClip?.name ?? '—';
  curDurEl.textContent = currentClip
    ? `${currentClip.duration.toFixed(2)}s (${Math.round(currentClip.duration * 60)} f)`
    : '—';
  curSrcEl.textContent = currentCharacter
    ? (SOURCE_INFO[currentCharacter.id] ?? '—')
    : '—';
}

// ---- Sidebar builders ----

function buildCharList() {
  charListEl.innerHTML = '';
  for (const c of ROSTER) {
    const el = document.createElement('div');
    el.className = 'item';
    el.dataset.charId = c.id;
    el.innerHTML = `<div>${c.name}</div><div class="meta">${c.region}</div>`;
    el.addEventListener('click', () => {
      document.querySelectorAll('#char-list .item').forEach((e) => e.classList.remove('active'));
      el.classList.add('active');
      loadCharacter(c);
    });
    charListEl.appendChild(el);
  }
}

function buildAnimList() {
  animListEl.innerHTML = '';
  for (const name of CANONICAL_ANIMATIONS) {
    const el = document.createElement('div');
    el.className = 'item';
    el.dataset.animName = name;
    el.textContent = name;
    el.addEventListener('click', () => playClipByName(name));
    animListEl.appendChild(el);
  }
  refreshAnimListMarkers();
}

function highlightActiveAnim(name) {
  document.querySelectorAll('#anim-list .item').forEach((e) => {
    e.classList.toggle('active', e.dataset.animName === name);
  });
}

function refreshAnimListMarkers() {
  if (!currentCharacter) return;
  document.querySelectorAll('#anim-list .item').forEach((e) => {
    const has = !!notesState[noteKey(currentCharacter.id, e.dataset.animName)];
    e.classList.toggle('has-note', has);
  });
}

// ---- Event handlers (set up AFTER DOM refs exist) ----

if (notesEl) {
  notesEl.addEventListener('input', () => {
    if (!currentCharacter || !currentClip) return;
    const key = noteKey(currentCharacter.id, currentClip.name);
    if (notesEl.value.trim() === '') delete notesState[key];
    else notesState[key] = notesEl.value;
    saveNotes(notesState);
    renderNotesSummary();
    refreshAnimListMarkers();
  });
}

if (exportBtn) {
  exportBtn.addEventListener('click', () => {
    const payload = { exportedAt: new Date().toISOString(), notes: notesState };
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `dsf-animation-feedback-${Date.now()}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(a.href);
  });
}

if (clearBtn) {
  clearBtn.addEventListener('click', () => {
    if (!confirm('Delete ALL notes for every character and animation?')) return;
    notesState = {};
    saveNotes(notesState);
    if (notesEl) notesEl.value = '';
    renderNotesSummary();
    refreshAnimListMarkers();
  });
}

playBtn?.addEventListener('click', () => {
  if (!currentAction) return;
  isPaused = !isPaused;
  currentAction.paused = isPaused;
  playBtn.textContent = isPaused ? '▶ Play' : '⏸ Pause';
});
speedEl?.addEventListener('input', () => {
  speedValEl.textContent = (+speedEl.value).toFixed(2) + 'x';
  if (currentAction) currentAction.timeScale = +speedEl.value;
});
loopEl?.addEventListener('change', () => {
  if (!currentAction) return;
  currentAction.setLoop(loopEl.checked ? THREE.LoopRepeat : THREE.LoopOnce, Infinity);
});
scrubEl?.addEventListener('mousedown', () => { scrubbing = true; });
scrubEl?.addEventListener('mouseup', () => { scrubbing = false; });
scrubEl?.addEventListener('input', () => {
  if (!currentAction || !currentClip) return;
  currentAction.time = +scrubEl.value;
  currentAction.paused = true;
  playBtn.textContent = '▶ Play';
  isPaused = true;
});

// ---- Frame loop ----

let lastT = performance.now();
function frame(now) {
  const dt = Math.min((now - lastT) / 1000, 1 / 30);
  lastT = now;
  if (currentAsset?.mixer && !isPaused) currentAsset.mixer.update(dt);
  if (currentAction && currentClip) {
    if (!scrubbing) scrubEl.value = currentAction.time.toFixed(3);
    const f = Math.floor(currentAction.time * 60);
    const total = Math.floor(currentClip.duration * 60);
    frameValEl.textContent = `${f} / ${total}`;
  }
  controls.update();
  renderer.render(scene, camera);
  requestAnimationFrame(frame);
}

// ---- Boot ----

buildCharList();
buildAnimList();
renderNotesSummary();

if (ROSTER[0]) {
  charListEl.firstChild?.classList.add('active');
  loadCharacter(ROSTER[0]);
}

requestAnimationFrame(frame);

if (import.meta.env.DEV) {
  window.__dsfViewer = { assetLoader, scene, camera, controls, renderer };
}
